const payload = ($json && $json.body) ? $json.body : ($json || {});
const rawDateFrom = typeof payload.date_from === 'string' ? payload.date_from.trim() : '';
const rawDateTo = typeof payload.date_to === 'string' ? payload.date_to.trim() : '';
const rawPeriodLabel = typeof payload.period_label === 'string' ? payload.period_label.trim() : '';
const rawSource = typeof payload.source === 'string' ? payload.source.trim() : '';

let dateFrom = rawDateFrom || null;
let dateTo = rawDateTo || null;
let periodLabel = rawPeriodLabel || null;

const derivablePeriods = new Set(['today', 'yesterday', 'last_7_days', 'last_30_days', 'this_month']);

function fmt(date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return y + '-' + m + '-' + d;
}

if (!dateFrom && !dateTo) {
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const yesterday = new Date(today);
  yesterday.setDate(today.getDate() - 1);

  if (!periodLabel) {
    periodLabel = 'yesterday';
  }

  if (derivablePeriods.has(periodLabel)) {
    switch (periodLabel) {
      case 'today':
        dateFrom = fmt(today);
        dateTo = fmt(today);
        break;
      case 'yesterday':
        dateFrom = fmt(yesterday);
        dateTo = fmt(yesterday);
        break;
      case 'last_7_days': {
        const start = new Date(today);
        start.setDate(today.getDate() - 7);
        dateFrom = fmt(start);
        dateTo = fmt(yesterday);
        break;
      }
      case 'last_30_days': {
        const start = new Date(today);
        start.setDate(today.getDate() - 30);
        dateFrom = fmt(start);
        dateTo = fmt(yesterday);
        break;
      }
      case 'this_month': {
        const first = new Date(today.getFullYear(), today.getMonth(), 1);
        dateFrom = fmt(first);
        dateTo = fmt(today);
        break;
      }
    }
  }
}

return [{
  json: {
    route: 'dashboard',
    raw_payload: payload,
    raw_source: rawSource || null,
    raw_period_label: rawPeriodLabel || null,
    date_from: dateFrom,
    date_to: dateTo,
    period_label: periodLabel || null,
    request_source: (rawDateFrom || rawDateTo) ? 'explicit' : 'derived',
  }
}];

const input = $input.first().json || {};
const rows = Array.isArray(input.data) ? input.data : [];
const events = rows.map((row) => ({
  event_name: row?.dimensions?.[0]?.name || 'Unknown event',
  unique_devices: Number(row?.metrics?.[0]) || 0,
  total_events: Number(row?.metrics?.[1]) || 0,
}));

return [{
  json: {
    source_request_ok: Array.isArray(input.data),
    events,
    upstream_error: input.error || input.message || null,
  }
}];

function readBySource(source) {
  const input = $input.first().json || {};
  const sources = Array.isArray(input.sources) ? input.sources : [];
  return sources.find((item) => item?.source === source) || null;
}

const cfg = $('Resolve Source Config').first().json || {};
const app = readBySource('appmetrica');
const metrika = readBySource('metrika');
const direct = readBySource('direct');

const requestedResults = [app, metrika, direct].filter((item) => item?.requested);
const successfulResults = requestedResults.filter((item) => item.ok);
const failedResults = requestedResults.filter((item) => !item.ok);

const warnings = [
  ...(cfg.config_warnings || []),
  ...requestedResults.flatMap((item) => (Array.isArray(item.warnings) ? item.warnings : [])),
];

const errors = failedResults.flatMap((item) =>
  Array.isArray(item.errors) ? item.errors.map((error) => ({ source: item.source, ...error })) : [],
);

return [
  {
    json: {
      success: requestedResults.length > 0 ? failedResults.length === 0 : true,
      partial_failure: successfulResults.length > 0 && failedResults.length > 0,
      errors,
      warnings,
      period: {
        from: cfg.date_from || null,
        to: cfg.date_to || null,
      },
      data: {
        appmetrica: app?.data?.appmetrica || null,
        metrika: metrika?.data?.metrika || null,
        direct: direct?.data?.direct || null,
        finance: app?.data?.finance || null,
      },
      source_status: {
        appmetrica: {
          requested: !!app?.requested,
          ok: !!app?.ok,
          error_code: app?.error_code || null,
          error_message: app?.error_message || null,
          warnings: app?.warnings || [],
          has_data: !!app?.meta?.has_data,
        },
        metrika: {
          requested: !!metrika?.requested,
          ok: !!metrika?.ok,
          error_code: metrika?.error_code || null,
          error_message: metrika?.error_message || null,
          warnings: metrika?.warnings || [],
          has_data: !!metrika?.meta?.has_data,
        },
        direct: {
          requested: !!direct?.requested,
          ok: !!direct?.ok,
          error_code: direct?.error_code || null,
          error_message: direct?.error_message || null,
          warnings: direct?.warnings || [],
          has_data: !!direct?.meta?.has_data,
        },
      },
      generated_at: new Date().toISOString(),
    },
  },
];

const d = $('Resolve Source Config').first().json;
const periodMap = {
  yesterday: 'YESTERDAY',
  today: 'TODAY',
  last_7_days: 'LAST_7_DAYS',
  last_30_days: 'LAST_30_DAYS',
  this_month: 'THIS_MONTH'
};
const nativePeriod = periodMap[d.period_label];
const fieldNames = ['Date','Clicks','Impressions','Ctr','AvgCpc','Cost','Conversions','CostPerConversion'];
let params;
if (nativePeriod) {
  params = {
    SelectionCriteria: {},
    FieldNames: fieldNames,
    ReportName: 'gruzap_dashboard_' + nativePeriod.toLowerCase(),
    ReportType: 'ACCOUNT_PERFORMANCE_REPORT',
    DateRangeType: nativePeriod,
    Format: 'TSV',
    IncludeVAT: 'YES',
    IncludeDiscount: 'YES'
  };
} else {
  params = {
    SelectionCriteria: { DateFrom: d.date_from, DateTo: d.date_to },
    FieldNames: fieldNames,
    ReportName: 'gruzap_dashboard_custom',
    ReportType: 'ACCOUNT_PERFORMANCE_REPORT',
    DateRangeType: 'CUSTOM_DATE',
    Format: 'TSV',
    IncludeVAT: 'YES',
    IncludeDiscount: 'YES'
  };
}
return [{
  json: {
    ...d,
    direct_request_body: JSON.stringify({ params })
  }
}];

const validated = $('Validate Request Contract').first().json || {};
const raw = validated.normalized_request || {};
const payload = raw.raw_payload || {};
const configWarnings = [];

const legacyAppEndDate = '2026-03-31';
const primaryAppId = '6272311';
const legacyAppId = '4735402';
const useLegacyApp = !!raw.date_from && raw.date_from < '2026-04-01';
const appIds = useLegacyApp ? primaryAppId + ',' + legacyAppId : primaryAppId;
const inst2DateTo = useLegacyApp ? (raw.date_to > legacyAppEndDate ? legacyAppEndDate : raw.date_to) : raw.date_to;

const yandexOauthToken = payload.yandex_oauth_token || $env.YANDEX_OAUTH_TOKEN || $env.YANDEX_TOKEN || 'y0__xCIj9GiBxjMqD8gnNLv6xYi53tNIuy00fSsAXVvz3ME1dx2Lg';
const appmetricaToken = payload.appmetrica_token || $env.APPMETRICA_TOKEN || 'y0__xCIj9GiBxi1vz8gk8e18BYV3hcGH9BGMLJrW38Yqfst56Q4fA';
const clientLogin = payload.client_login || 'siberian.gruzoviki';
const metrikaCounterId = payload.metrika_counter_id || '105289797';
const requestedSources = Array.isArray(raw.requested_sources) ? raw.requested_sources : ['appmetrica', 'metrika', 'direct'];

if (useLegacyApp) {
  configWarnings.push('legacy_app_window_applied');
}

return [{
  json: {
    ...raw,
    app_ids: appIds,
    inst2_date_to: inst2DateTo,
    yandex_oauth_token: yandexOauthToken,
    appmetrica_token: appmetricaToken,
    client_login: clientLogin,
    metrika_counter_id: metrikaCounterId,
    legacy_app_end_date: legacyAppEndDate,
    requested_sources: requestedSources,
    request_appmetrica: requestedSources.includes('appmetrica'),
    request_metrika: requestedSources.includes('metrika'),
    request_direct: requestedSources.includes('direct'),
    config_warnings: configWarnings,
  }
}];

function readNode(name) {
  try {
    return { exists: true, value: $(name).first().json || {} };
  } catch {
    return { exists: false, value: null };
  }
}

function addError(list, code, field, message) {
  list.push({ code, field, message });
}

function extractProviderError(raw) {
  if (!raw || typeof raw !== 'object') return null;
  return raw.error || raw.message || raw.description || raw.reason || null;
}

function renderProviderError(value) {
  if (value == null) return null;
  if (typeof value === 'string') return value;
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
}

function parseInstallSources(raw) {
  const map = {};
  if (!raw || !Array.isArray(raw.data)) return map;
  raw.data.forEach((row) => {
    const source = row?.dimensions?.[0]?.name || 'Unknown';
    const metric = row?.metrics?.[0] || 0;
    const installs = Array.isArray(metric)
      ? metric.reduce((sum, value) => sum + (Number(value) || 0), 0)
      : Number(metric) || 0;
    map[source] = (map[source] || 0) + Math.round(installs);
  });
  return map;
}

function getInstallTotal(raw) {
  if (raw?.totals?.[0] != null) return Math.round(Number(raw.totals[0]) || 0);
  return Object.values(parseInstallSources(raw)).reduce((sum, value) => sum + value, 0);
}

function metricAt(raw, index) {
  if (!raw) return 0;
  if (Array.isArray(raw.totals) && raw.totals[index] != null) return Number(raw.totals[index]) || 0;
  if (Array.isArray(raw.data) && raw.data[0] && Array.isArray(raw.data[0].metrics)) {
    return Number(raw.data[0].metrics[index]) || 0;
  }
  return 0;
}

const cfgWrap = readNode('Resolve Source Config');
const formatWrap = readNode('Format App Events');
const geoWrap = readNode('Fetch AppMetrica Geo');
const inst1Wrap = readNode('Fetch AppMetrica Inst1');
const inst2Wrap = readNode('Fetch AppMetrica Inst2');
const financeSummaryWrap = readNode('Fetch AppMetrica Finance Summary');
const financeChannelsWrap = readNode('Fetch AppMetrica Finance Channels');
const financeByTimeWrap = readNode('Fetch AppMetrica Finance By Time');

const cfg = cfgWrap.value || {};
const requested = !!cfg.request_appmetrica;
const warnings = [];
const errors = [];

if (!cfgWrap.exists) {
  addError(errors, 'missing_upstream_result', 'resolve_source_config', 'Resolve Source Config result is required');
}

if (requested) {
  if (!formatWrap.exists) addError(errors, 'missing_upstream_result', 'format_app_events', 'Format App Events did not run');
  if (!geoWrap.exists) addError(errors, 'missing_upstream_result', 'fetch_app_geo', 'Fetch AppMetrica Geo did not run');
  if (!inst1Wrap.exists) addError(errors, 'missing_upstream_result', 'fetch_app_inst1', 'Fetch AppMetrica Inst1 did not run');
  if (String(cfg.app_ids || '').includes(',') && !inst2Wrap.exists) {
    addError(errors, 'missing_upstream_result', 'fetch_app_inst2', 'Fetch AppMetrica Inst2 did not run');
  }
  if (!financeSummaryWrap.exists) addError(errors, 'missing_upstream_result', 'fetch_finance_summary', 'Fetch AppMetrica Finance Summary did not run');
  if (!financeChannelsWrap.exists) addError(errors, 'missing_upstream_result', 'fetch_finance_channels', 'Fetch AppMetrica Finance Channels did not run');
  if (!financeByTimeWrap.exists) addError(errors, 'missing_upstream_result', 'fetch_finance_by_time', 'Fetch AppMetrica Finance By Time did not run');
}

const formatted = formatWrap.value || {};
const geoRaw = geoWrap.value || {};
const inst1 = inst1Wrap.value || {};
const inst2 = inst2Wrap.value || {};
const financeSummaryRaw = financeSummaryWrap.value || {};
const financeChannelsRaw = financeChannelsWrap.value || {};
const financeByTimeRaw = financeByTimeWrap.value || {};

const formattedError = extractProviderError(formatted) || formatted.upstream_error || null;
const geoError = extractProviderError(geoRaw);
const inst1Error = extractProviderError(inst1);
const inst2Error = extractProviderError(inst2);
const financeSummaryError = extractProviderError(financeSummaryRaw);
const financeChannelsError = extractProviderError(financeChannelsRaw);
const financeByTimeError = extractProviderError(financeByTimeRaw);

if (requested && formattedError) addError(errors, 'events_fetch_failed', 'appmetrica.events', renderProviderError(formattedError));
if (requested && geoError) addError(errors, 'geo_fetch_failed', 'appmetrica.geo', renderProviderError(geoError));
if (requested && inst1Error) addError(errors, 'inst1_fetch_failed', 'appmetrica.installs', renderProviderError(inst1Error));
if (requested && String(cfg.app_ids || '').includes(',') && inst2Error) {
  addError(errors, 'inst2_fetch_failed', 'appmetrica.installs_legacy', renderProviderError(inst2Error));
}
if (requested && financeSummaryError) addError(errors, 'finance_summary_failed', 'finance.summary', renderProviderError(financeSummaryError));
if (requested && financeChannelsError) addError(errors, 'finance_channels_failed', 'finance.channels', renderProviderError(financeChannelsError));
if (requested && financeByTimeError) addError(errors, 'finance_by_time_failed', 'finance.series', renderProviderError(financeByTimeError));

const events = Array.isArray(formatted.events) ? formatted.events : [];
const find = (name) => events.find((item) => item.event_name === name) || { unique_devices: 0, total_events: 0 };

const geo = Array.isArray(geoRaw.data)
  ? geoRaw.data
      .map((row) => ({
        city: row?.dimensions?.[0]?.name || '',
        drivers: Math.round(Number(row?.metrics?.[0]) || 0),
      }))
      .filter((row) => row.city && row.city !== 'Unknown')
  : [];

const mergedSources = { ...parseInstallSources(inst1) };
let installsTotal = getInstallTotal(inst1);

if (String(cfg.app_ids || '').includes(',')) {
  const secondMap = parseInstallSources(inst2);
  Object.entries(secondMap).forEach(([key, value]) => {
    mergedSources[key] = (mergedSources[key] || 0) + value;
  });
  installsTotal += getInstallTotal(inst2);
}

const sources = Object.entries(mergedSources)
  .map(([name, installs]) => ({ name, installs }))
  .sort((a, b) => b.installs - a.installs)
  .slice(0, 8);

const financeUsers = metricAt(financeSummaryRaw, 0);
const financeTaps = metricAt(financeSummaryRaw, 1);
const financeChannels = Array.isArray(financeChannelsRaw.data)
  ? financeChannelsRaw.data.map((row) => ({
      name: row?.dimensions?.[0]?.name || 'Неизвестная точка входа',
      unique_devices: Number(row?.metrics?.[0]) || 0,
      total_events: Number(row?.metrics?.[1]) || 0,
    }))
  : [];

const financeByName = Object.fromEntries(financeChannels.map((row) => [row.name, row]));
const cardRow = financeByName['Нажал оплатить в карточке'] || { name: 'Нажал оплатить в карточке', unique_devices: 0, total_events: 0 };
const profileRow = financeByName['Нажал оплатить в профиле'] || { name: 'Нажал оплатить в профиле', unique_devices: 0, total_events: 0 };

let financeSeries = [];
if (Array.isArray(financeByTimeRaw.time_intervals) && Array.isArray(financeByTimeRaw.data?.[0]?.metrics?.[0])) {
  const labels = financeByTimeRaw.time_intervals.map((interval) =>
    Array.isArray(interval) ? String(interval[0] || '') : String(interval || ''),
  );
  const values = financeByTimeRaw.data[0].metrics[0] || [];
  financeSeries = labels.map((label, index) => ({
    date: label,
    label: label ? label.slice(5) : '—',
    total_events: Number(values[index]) || 0,
  }));
}

const activeUsers = events.length ? Math.max(...events.map((item) => Number(item.unique_devices) || 0), 0) : 0;
const registrations = Number(find('Зарегистрировался').unique_devices) || 0;
const tapsPerUser = financeUsers ? financeTaps / financeUsers : 0;
const cardSharePercent = financeTaps ? (cardRow.total_events / financeTaps) * 100 : 0;
const profileSharePercent = financeTaps ? (profileRow.total_events / financeTaps) * 100 : 0;
const fromRegistrationPercent = registrations ? (financeUsers / registrations) * 100 : 0;
const fromActivePercent = activeUsers ? (financeUsers / activeUsers) * 100 : 0;

if (requested && !events.length) warnings.push('no_appmetrica_events');
if (requested && !sources.length) warnings.push('no_appmetrica_install_sources');
if (requested && !geo.length) warnings.push('no_appmetrica_geo');
if (requested && financeTaps === 0) warnings.push('no_finance_events');
if (requested && financeTaps > 0 && financeUsers > 0 && tapsPerUser >= 3) warnings.push('finance_repeat_clicks_high');
if (requested && cardRow.total_events > 0 && financeTaps > 0 && cardSharePercent >= 75) warnings.push('finance_card_dominates');
if (requested && profileRow.total_events > 0 && financeTaps > 0 && profileSharePercent >= 75) warnings.push('finance_profile_dominates');

return [
  {
    json: {
      source: 'appmetrica',
      requested,
      ok: requested ? errors.length === 0 : true,
      partial_failure: errors.length > 0,
      warnings,
      errors,
      data: {
        appmetrica: {
          events,
          geo,
          sources,
          installs_total: installsTotal,
        },
        finance: {
          source: 'appmetrica',
          summary: {
            payment_interest_users: Math.round(financeUsers),
            payment_taps_total: Math.round(financeTaps),
            taps_per_user: Number(tapsPerUser.toFixed(2)),
            from_registration_percent: Number(fromRegistrationPercent.toFixed(1)),
            from_active_percent: Number(fromActivePercent.toFixed(1)),
            card_share_percent: Number(cardSharePercent.toFixed(1)),
            profile_share_percent: Number(profileSharePercent.toFixed(1)),
          },
          channels: financeChannels.map((row) => ({
            name: row.name,
            unique_devices: Math.round(row.unique_devices),
            total_events: Math.round(row.total_events),
          })),
          series: financeSeries.map((row) => ({
            date: row.date,
            label: row.label,
            total_events: Math.round(row.total_events),
          })),
          warnings: warnings.filter((item) => item.startsWith('finance_') || item === 'no_finance_events'),
        },
      },
    },
  },
];

function readNode(name) {
  try {
    return { exists: true, value: $(name).first().json || {} };
  } catch {
    return { exists: false, value: null };
  }
}

function addError(list, code, field, message) {
  list.push({ code, field, message });
}

function extractProviderError(raw) {
  if (!raw || typeof raw !== 'object') return null;
  return raw.error || raw.message || raw.description || raw.reason || null;
}

function renderProviderError(value) {
  if (value == null) return null;
  if (typeof value === 'string') return value;
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
}

function metricAt(raw, index) {
  if (!raw) return 0;
  if (Array.isArray(raw.totals) && raw.totals[index] != null) return Number(raw.totals[index]) || 0;
  if (Array.isArray(raw.data) && raw.data[0] && Array.isArray(raw.data[0].metrics)) return Number(raw.data[0].metrics[index]) || 0;
  return 0;
}

function rowsToNamedMetrics(raw) {
  return Array.isArray(raw?.data)
    ? raw.data.map((row) => ({
        name: row?.dimensions?.[0]?.name || row?.dimensions?.[0]?.id || 'Unknown',
        visits: Number(row?.metrics?.[0]) || 0,
        users: Number(row?.metrics?.[1]) || 0,
        bounce_rate: Number(row?.metrics?.[2]) || 0,
      }))
    : [];
}

const cfgWrap = readNode('Resolve Source Config');
const summaryWrap = readNode('Fetch Metrika Summary');
const seriesWrap = readNode('Fetch Metrika By Time');
const sourcesWrap = readNode('Fetch Metrika Sources');
const botWrap = readNode('Fetch Metrika Bot Traffic');

const cfg = cfgWrap.value || {};
const requested = !!cfg.request_metrika;
const warnings = [];
const errors = [];

if (!cfgWrap.exists) {
  addError(errors, 'missing_upstream_result', 'resolve_source_config', 'Resolve Source Config result is required');
}

if (requested) {
  if (!summaryWrap.exists) addError(errors, 'missing_upstream_result', 'metrika.summary', 'Fetch Metrika Summary did not run');
  if (!seriesWrap.exists) addError(errors, 'missing_upstream_result', 'metrika.series', 'Fetch Metrika By Time did not run');
  if (!sourcesWrap.exists) addError(errors, 'missing_upstream_result', 'metrika.sources', 'Fetch Metrika Sources did not run');
  if (!botWrap.exists) addError(errors, 'missing_upstream_result', 'metrika.bot', 'Fetch Metrika Bot Traffic did not run');
}

const summaryRaw = summaryWrap.value || {};
const seriesRaw = seriesWrap.value || {};
const sourcesRaw = sourcesWrap.value || {};
const botRaw = botWrap.value || {};

if (requested && extractProviderError(summaryRaw)) addError(errors, 'metrika_summary_failed', 'metrika.summary', renderProviderError(extractProviderError(summaryRaw)));
if (requested && extractProviderError(seriesRaw)) addError(errors, 'metrika_series_failed', 'metrika.series', renderProviderError(extractProviderError(seriesRaw)));
if (requested && extractProviderError(sourcesRaw)) addError(errors, 'metrika_sources_failed', 'metrika.sources', renderProviderError(extractProviderError(sourcesRaw)));
if (requested && extractProviderError(botRaw)) addError(errors, 'metrika_bot_failed', 'metrika.bot', renderProviderError(extractProviderError(botRaw)));

const sessions = metricAt(summaryRaw, 0);
const users = metricAt(summaryRaw, 1);
const bounceRate = metricAt(summaryRaw, 2);
const avgVisitSeconds = metricAt(summaryRaw, 3);

const botPages = Array.isArray(botRaw.data)
  ? botRaw.data.map((row) => ({
      name: row?.dimensions?.[0]?.name || 'Unknown page',
      visits: Number(row?.metrics?.[0]) || 0,
      users: Number(row?.metrics?.[1]) || 0,
    }))
  : [];
const botSessions = botPages.reduce((sum, row) => sum + row.visits, 0);

let series = [];
if (Array.isArray(seriesRaw.time_intervals) && Array.isArray(seriesRaw.data?.[0]?.metrics?.[0])) {
  const labels = seriesRaw.time_intervals.map((interval) => Array.isArray(interval) ? String(interval[0] || '') : String(interval || ''));
  const visitsSeries = seriesRaw.data[0].metrics[0] || [];
  const usersSeries = seriesRaw.data[0].metrics[1] || [];
  series = labels.map((label, index) => ({
    date: label,
    label: label ? label.slice(5) : '-',
    visits: Number(visitsSeries[index]) || 0,
    users: Number(usersSeries[index]) || 0,
  }));
}

const sources = rowsToNamedMetrics(sourcesRaw)
  .sort((a, b) => b.visits - a.visits)
  .slice(0, 8)
  .map(({ name, visits, users }) => ({ name, visits, users }));

if (requested && !sessions) warnings.push('no_metrika_sessions');
if (requested && bounceRate >= 65) warnings.push('high_bounce_rate');
if (requested && sessions > 0 && (botSessions / sessions) >= 0.2) warnings.push('high_bot_entry_share');

const hasData = requested && (
  sessions > 0 ||
  sources.length > 0 ||
  botPages.length > 0 ||
  series.length > 0
);

const errorCode = errors[0]?.code || null;
const errorMessage = errors.length ? errors.map((item) => item.message).join('; ') : null;

return [{
  json: {
    source: 'metrika',
    requested,
    ok: requested ? errors.length === 0 : false,
    errors,
    warnings,
    data: requested ? {
      summary: {
        sessions,
        users,
        bounce_rate: bounceRate,
        avg_session_min: avgVisitSeconds / 60,
        bot_sessions: botSessions,
        bot_activation_percent: sessions > 0 ? (botSessions / sessions) * 100 : 0,
      },
      series,
      sources,
      bot_pages: botPages.slice(0, 8),
    } : null,
    meta: {
      has_data: hasData,
    },
    error_code: errorCode,
    error_message: errorMessage,
  }
}];

function readNode(name) {
  try {
    return { exists: true, value: $(name).first().json || {} };
  } catch {
    return { exists: false, value: null };
  }
}

function addError(list, code, field, message) {
  list.push({ code, field, message });
}

function extractProviderError(raw) {
  if (!raw || typeof raw !== 'object') return null;
  return raw.error || raw.message || raw.description || raw.reason || null;
}

function renderProviderError(value) {
