    success: false,
    partial_failure: false,
    errors: Array.isArray(input.errors) ? input.errors : [{
      code: 'invalid_ai_response',
      field: 'analysis',
      message: 'AI response did not pass validation',
    }],
    warnings: Array.isArray(input.warnings) ? input.warnings : [],
    tab: input.tab || null,
    period_name: input.period_name || '',
    analysis: null,
    analysis_text: null,
    model: input.model || 'claude-sonnet-4-5-20250929',
  }
}];

const input = $('Validate AI Response Contract').first().json || {};
const analysis = input.analysis || null;

function renderAnalysisText(value) {
  if (!value) return null;
  return [
    value.title,
    '',
    'Вердикт: ' + value.verdict,
    '',
    'Что хорошо:',
    ...value.good.map((item) => '- ' + item),
    '',
    'Что ухудшает результат:',
    ...value.bad.map((item) => '- ' + item),
    '',
    'Что делать дальше:',
    ...value.next_steps.map((item, index) => String(index + 1) + '. ' + item),
    '',
    'Уровень уверенности: ' + value.confidence,
  ].join('\n');
}

return [{
  json: {
    success: true,
    partial_failure: false,
    errors: [],
    warnings: [],
    tab: input.tab || null,
    period_name: input.period_name || '',
    analysis,
    analysis_text: renderAnalysisText(analysis),
    model: input.model || 'claude-sonnet-4-5-20250929',
  }
}];
